  let params = route.split('/').slice(1);
  let expectedParams = ['id', 'id', 'postId', 'postId'];
  for (let i = 0; i < params.length; i++) {
    if (params[i] !== expectedParams[i]) {
      return false;
    }
  }
  return true;
}

